// Semantic markdown chunker.
// Splits the document on level-2 (##) headings, falling back to the
// whole document under a "General" section if no headings are found.
// Produces one JSON item per document (chunks nested inside), which the
// next Split Out node will explode into one item per chunk.

const crypto = require('crypto');

const text = $input.first().json.data || $input.first().json.text || '';
const binary = $input.first().binary && $input.first().binary.data;
const fileName = binary ? binary.fileName : ($input.first().json.fileName || 'unknown.md');

// Derive a readable title from the first H1, or from the filename.
const h1Match = text.match(/^#\s+(.+)$/m);
const title = h1Match ? h1Match[1].trim() : fileName.replace(/\.md$/i, '').replace(/[-_]/g, ' ');

// Split into sections by "## Heading" boundaries, keeping the heading text.
const sectionRegex = /^##\s+(.+)$/gm;
let sections = [];
let lastIndex = 0;
let lastHeading = 'General';
let match;

while ((match = sectionRegex.exec(text)) !== null) {
  const chunkText = text.slice(lastIndex, match.index).trim();
  if (chunkText.length > 0) {
    sections.push({ heading: lastHeading, content: chunkText });
  }
  lastHeading = match[1].trim();
  lastIndex = match.index;
}
// final trailing section
const tail = text.slice(lastIndex).trim();
if (tail.length > 0) {
  sections.push({ heading: lastHeading, content: tail });
}
if (sections.length === 0) {
  sections.push({ heading: 'General', content: text.trim() });
}

// Strip the heading marker itself out of the content body and drop the H1 title line.
sections = sections.map(s => {
  let content = s.content
    .replace(/^##\s+.+$/m, '')
    .replace(/^#\s+.+$/m, '')
    .trim();
  return { heading: s.heading, content };
}).filter(s => s.content.length > 0);

// Further split any very long section (> ~500 tokens ~ 2000 chars) into
// overlapping sub-chunks so no single chunk overwhelms the context window.
const MAX_CHARS = 2000;
const OVERLAP_CHARS = 200;
const finalChunks = [];
let chunkIndex = 0;

for (const section of sections) {
  if (section.content.length <= MAX_CHARS) {
    finalChunks.push({
      section: section.heading,
      content: section.content,
      chunk_index: chunkIndex++
    });
  } else {
    let start = 0;
    while (start < section.content.length) {
      const end = Math.min(start + MAX_CHARS, section.content.length);
      finalChunks.push({
        section: section.heading,
        content: section.content.slice(start, end).trim(),
        chunk_index: chunkIndex++
      });
      start = end - OVERLAP_CHARS;
      if (start <= 0 || end === section.content.length) break;
    }
  }
}

const checksum = 'sha256:' + crypto.createHash('sha256').update(text).digest('hex');

return [{
  json: {
    title,
    source_path: fileName,
    checksum,
    chunks: finalChunks
  }
}];

const doc = $input.first().json[0] || $input.first().json;
const chunkData = $('Chunk Markdown').first().json;
const documentId = doc.id;
const documentTitle = doc.title;

return chunkData.chunks.map(c => ({
  json: {
    document_id: documentId,
    document_title: documentTitle,
    section: c.section,
    chunk_index: c.chunk_index,
    content: c.content
  }
}));

const items = $input.all();
return items.map((item, i) => {
  const embedding = item.json.data[0].embedding;
  const chunkMeta = $('Attach Document Id').all()[i].json;
  return {
    json: {
      ...chunkMeta,
      embedding,
      token_count: item.json.usage ? item.json.usage.total_tokens : null
    }
  };
});
